            username: string;
            password: string;
            /** @description centralized_login 场景下的目标业务 APP */
            target_app_key?: string;
            /** @description centralized_login 场景下的 callback 绝对地址 */
            redirect_uri?: string;
            /** @description 登录成功后最终回跳的业务页相对路径 */
            target_path?: string;
